import 'package:flutter_test/flutter_test.dart'; import 'package:googlepro/features/qr_pairing/model/pairing_data.dart'; void main() { group('QrPairing', () { test('toQrString generates valid JSON', () { final d = PairingData(deviceId: 'd1', deviceName: 'Dev', ownerUid: 'uid1', timestamp: 1000); final s = d.toQrString(); expect(s.contains('d1'), true); }); test('fromQrString restores data', () { final d = PairingData(deviceId: 'd1', deviceName: 'Dev', ownerUid: 'uid1', timestamp: DateTime.now().millisecondsSinceEpoch); final s = d.toQrString(); final r = PairingData.fromQrString(s); expect(r?.deviceId, 'd1'); }); test('old QR code is expired', () { final d = PairingData(deviceId: 'd1', deviceName: 'D', ownerUid: 'u', timestamp: 0); expect(d.isExpired, true); }); }); }